        builder.variable(new VariableDef("capital depreciation", "The rate at which the capital stock depreciates.", "Capital * capital_depreciation_normal", "Capital units / Year"));
        builder.variable(new VariableDef("food ratio", "The ration of food available to required food.", "food_per_capita_potential * food_crowding_multiplier * food_pollution_multiplier * food_coefficient / food_per_capita_normal", "Dimensionless"));
        builder.variable(new VariableDef("births", "The total number of births.", "Population * birth_rate_normal * births_material_multiplier * births_crowding_multiplier * births_food_multiplier * births_pollution_multiplier", "People / Year"));
        builder.variable(new VariableDef("pollution generation", "The rate at which non-ncorporate poltion changes.", "Population * pollution_per_capita_normal * pollution_capital_multiplier", "Pollution units / Year"));
        builder.variable(new VariableDef("natural resource utilization", "The rate of natural resource utilization.", "Population * natural_resource_utilization_normal * nat_res_matl_multiplier", "Resource units / Year"));
        builder.variable(new VariableDef("deaths", "The worldwide number of deaths occurring.", "Population * death_rate_normal * deaths_material_multiplier * deaths_pollution_multiplier * deaths_food_multiplier * deaths_crowding_multiplier", "People / Year"));
        builder.variable(new VariableDef("capital investment", "The gross amount of investment in capital.", "Population * capital_investment_multiplier * capital_investment_rate_normal", "Capital units / Year"));
        builder.variable(new VariableDef("births crowding multiplier", "The effect of crowding on the number of births.", "LOOKUP(births_crowding_mult_tab, crowding)", "Dimensionless"));
        builder.variable(new VariableDef("births food multiplier", "The effect of food on the number of births.", "LOOKUP(births_food_mult_tab, food_ratio)", "Dimensionless"));
        builder.variable(new VariableDef("births material multiplier", "The effect of the material standard of living on births.", "LOOKUP(births_material_mult_tab, material_standard_of_living)", "Dimensionless"));
        builder.variable(new VariableDef("births pollution multiplier", "The effect of pollution on the number of births.", "LOOKUP(births_pollution_mult_tab, pollution_ratio)", "Dimensionless"));
