        builder.variable(new VariableDef("capital investment from quality ratio", "Capital investment from quality.", "LOOKUP(capital_investment_quality_ratio_tab, quality_material_multiplier / quality_food_multiplier)", "Dimensionless"));
        builder.variable(new VariableDef("capital investment multiplier", "Multiplier for the effect of the material standard of\n\t\t         living on\n\t\t         capital investment.", "LOOKUP(capital_investment_mult_tab, material_standard_of_living)", "Dimensionless"));
        builder.variable(new VariableDef("capital ratio", "The capital investment ratio (per capita investment).", "Capital / Population", "Capital units / Person"));
        builder.variable(new VariableDef("capital ratio agriculture", "The capital investment ratio in agriculure.", "capital_ratio * Capital_Agriculture_Fraction / capital_agriculture_fraction_normal", "Capital units / Person"));
        builder.variable(new VariableDef("crowding", "The ratio oioulation to normally supportable population\n\t\t         used as a\n\t\t         measure of crowding.", "Population / ( land_area * population_density_normal )", "Dimensionless"));
        builder.variable(new VariableDef("deaths crowding multiplier", "The effect of crowding on the number of deaths.", "LOOKUP(deaths_crowding_mult_tab, crowding)", "Dimensionless"));
        builder.variable(new VariableDef("deaths food multiplier", "The effect of food on the number of deaths.", "LOOKUP(deaths_food_mult_tab, food_ratio)", "Dimensionless"));
        builder.variable(new VariableDef("deaths material multiplier", "The effect of the material standard of living on deaths.", "LOOKUP(deaths_material_mult_tab, material_standard_of_living)", "Dimensionless"));
        builder.variable(new VariableDef("deaths pollution multiplier", "The effect of pollution on the number of deaths.", "LOOKUP(deaths_pollution_mult_tab, pollution_ratio)", "Dimensionless"));
        builder.variable(new VariableDef("effective capital ratio", "The effective ratio between capital and investment.", "capital_ratio * natural_resource_extraction_multiplier * ( 1 - Capital_Agriculture_Fraction ) / ( 1 - capital_agriculture_fraction_normal )", "Capital units / Person"));
        builder.variable(new VariableDef("food crowding multiplier", "The effect of crowding on the production of food.", "LOOKUP(food_crowding_mult_tab, crowding)", "Dimensionless"));
        builder.variable(new VariableDef("food per capita potential", "The potential amount of food that can be grown based on\n\t\t         capital\n\t\t         investment.", "LOOKUP(food_per_capita_potential_tab, capital_ratio_agriculture)", "Food units / Person / Year"));
        builder.variable(new VariableDef("food pollution multiplier", "The effect of pollution on the ability to grow food.", "LOOKUP(food_pollution_mult_tab, pollution_ratio)", "Dimensionless"));
        builder.variable(new VariableDef("material standard of living", "The relative material standard of living.", "effective_capital_ratio / effective_capital_ratio_normal", "Dimensionless"));
        builder.variable(new VariableDef("natural resource fraction remaining", "The fraction of natural resource still remaining.", "Natural_Resources / natural_resources_initial", "Dimensionless"));
        builder.variable(new VariableDef("nat res matl multiplier", "The effect of the material well being on natural resource\n\t\t         use.", "LOOKUP(natural_resource_material_mult_tab, material_standard_of_living)", "Dimensionless"));
        builder.variable(new VariableDef("natural resource extraction multiplier", "The multiplier on effective capital investment from\n\t\t         remaining natural\n\t\t         resources.", "LOOKUP(natural_resource_extraction_mult_tab, natural_resource_fraction_remaining)", "Dimensionless"));
